  ('Naritaya Halal Ramen', '成田屋 ハラールラーメン', '1-17-4 Asakusa, Taito-ku, Tokyo', '東京都台東区浅草1-17-4', 35.7118, 139.7954, 'WGS84', 'japanese', 1, 1, 'One of Tokyo''s first fully Halal-certified ramen shops, located near Sensoji Temple in Asakusa. Popular with Muslim tourists.', '{}', true, 0),
  ('Gyumon Halal Yakiniku', '牛門 ハラール焼肉', '3-25-3 Shinjuku, Shinjuku-ku, Tokyo', '東京都新宿区新宿3-25-3', 35.6905, 139.7005, 'WGS84', 'japanese', 3, 1, 'Halal Japanese BBQ restaurant in Shinjuku serving premium wagyu beef. Halal-certified with Arabic-speaking staff.', '{}', true, 0),
  ('Honolu Halal Bento', 'ホノル ハラール弁当', '2-11-5 Kabukicho, Shinjuku-ku, Tokyo', '東京都新宿区歌舞伎町2-11-5', 35.6951, 139.7028, 'WGS84', 'japanese', 1, 1, 'Affordable Halal bento boxes and set meals near Shinjuku Station. Great for a quick lunch.', '{}', true, 0),
  ('Sekai Cafe Asakusa', '世界カフェ 浅草', '1-18-10 Asakusa, Taito-ku, Tokyo', '東京都台東区浅草1-18-10', 35.7125, 139.7948, 'WGS84', 'other', 2, 1, 'Multicultural cafe near Sensoji offering Halal and vegetarian options. Good for coffee and light meals.', '{}', true, 0),
  ('Ayam-Ya Halal Chicken', 'アヤムヤ', '1-4-16 Hyakunincho, Shinjuku-ku, Tokyo', '東京都新宿区百人町1-4-16', 35.7007, 139.6998, 'WGS84', 'malaysian', 1, 1, 'Malaysian-style Halal chicken rice near Shin-Okubo. A favourite among the local Muslim community.', '{}', true, 0),
  ('Niu Jie Hui Min Restaurant', '牛街惠民小吃', 'Niu Jie, Xicheng District, Beijing', '北京市西城区牛街5号', 39.887, 116.358, 'WGS84', 'chinese_muslim', 1, 1, 'Traditional Hui Muslim snack shop on Niu Jie (Ox Street), Beijing''s historic Muslim quarter. Famous for niangao and fried dough.', '{}', true, 0),
  ('Hongbinlou Restaurant', '鸿宾楼', '11 Zhanlanguan Lu, Xicheng District, Beijing', '北京市西城区展览馆路11号', 39.9145, 116.3358, 'WGS84', 'chinese_muslim', 3, 1, 'Historic Halal restaurant established in 1853. Famous for Qingzhen (Halal) cuisine, especially lamb dishes and sesame cakes.', '{}', true, 0),
  ('Jingwei Mian Dawang', '京味面大王', '68 Niu Jie, Xicheng District, Beijing', '北京市西城区牛街68号', 39.8865, 116.3576, 'WGS84', 'chinese_muslim', 1, 1, 'Popular hand-pulled noodle shop in the Niu Jie Muslim quarter. Excellent beef noodle soup.', '{}', true, 0),
  ('Tuyuegou Halal Restaurant', '吐月沟新疆餐厅', 'Wudaokou, Haidian District, Beijing', '北京市海淀区五道口华清嘉园', 39.9927, 116.3381, 'WGS84', 'central_asian', 2, 1, 'Authentic Uyghur restaurant near Wudaokou. Known for da pan ji (big plate chicken), lamb kebabs, and hand-pulled laghman noodles.', '{}', true, 0),
  ('Donglaishun Hot Pot', '东来顺', '16 Jinyu Hutong, Dongcheng District, Beijing', '北京市东城区金鱼胡同16号', 39.9168, 116.4108, 'WGS84', 'chinese_muslim', 3, 1, 'Iconic Halal hot pot chain since 1903. Specialises in instant-boiled mutton (shuan yangrou). A Beijing institution.', '{}', true, 0),
  ('Lao Sun Jia Restaurant', '老孙家饭庄', '364 Dong Dajie, Beilin District, Xi''an', '西安市碑林区东大街364号', 34.2614, 108.954, 'WGS84', 'chinese_muslim', 2, 1, 'Century-old Halal restaurant famous for yangrou paomo (crumbled bread in lamb soup), Xi''an''s signature Muslim dish.', '{}', true, 0),
